sql:
SELECT station_id, batch_id, SUM(station_volume) AS total_volume
FROM production_batches
GROUP BY station_id, batch_id;

SELECT batch_id, station_volume
FROM production_batches
WHERE station_volume = (SELECT MAX(station_volume) FROM production_batches);

SELECT batch_name
FROM production_batches
WHERE station_volume > (SELECT AVG(station_volume) FROM production_batches);

SELECT pb.batch_name, s.station_name 
FROM production_batches pb
LEFT JOIN stations s ON pb.station_id = s.station_id;

SELECT batch_name
FROM production_batches
WHERE batch_id = 1;

external_knowledge:
- 'managers' refers to users with the role_name 'manager';
- 'top-priority' corresponds to a preference level of 1;
- 'long cycle times' means cycle_duration greater than 200 minutes;
- 'completed batches' have the status 'completed'.

